    if (el) return el.textContent.trim();
    return 'de BeleidsBibliotheek';
}
function toggleReactiePanel() {
    var panel = document.getElementById('rpPanel');
    var overlay = document.getElementById('rpOverlay');
    var fab = document.getElementById('fabReactie');
    var open = panel.classList.toggle('rp-open');
    overlay.classList.toggle('rp-overlay-open', open);
    fab.style.display = open ? 'none' : '';
    if (open) document.getElementById('rpContext').textContent = detectContext();
}

