var RP_BBV_NAAR_SECTIE = {
    0: 'H0 Bestuur en ondersteuning',
    1: 'H1 Veiligheid',
    2: 'H2 Verkeer, vervoer en waterstaat',
    3: 'H3 Economie',
    4: 'H4 Onderwijs',
    5: 'H5 Sport, cultuur en recreatie',
    6: 'H6 Sociaal domein',
    7: 'H7 Volksgezondheid en milieu',
    8: 'H8 VHROSV'
};
function rpTaakveldNaam(bbvIndex, code) {
    if (!code) return '';
    var tvs = (typeof BBV_TAAKVELDEN_PER_HOOFDSTUK !== 'undefined') ? BBV_TAAKVELDEN_PER_HOOFDSTUK[bbvIndex] : null;
    if (!tvs) return code;
    for (var i = 0; i < tvs.length; i++) {
        if (tvs[i].code === code) return tvs[i].code + ' ' + tvs[i].naam;
    }
    return code;
}
function detectContext() {
    if (typeof activeDossier !== 'undefined' && activeDossier) {
        if (activeDossier.bbvMode && activeDossier.bbvIndex !== undefined) {
            var hoofdstuk = RP_BBV_NAAR_SECTIE[activeDossier.bbvIndex] || activeDossier.domein;
            if (activeDossier.subFilter) {
                var tvNaam = rpTaakveldNaam(activeDossier.bbvIndex, activeDossier.subFilter);
                return hoofdstuk + ' \u2192 ' + tvNaam;
            }
            return hoofdstuk || 'de BeleidsBibliotheek';
        }
        if (activeDossier.domein) return activeDossier.domein;
    }
    if (typeof viewMode !== 'undefined' && viewMode === 'overdrachtsdossier') return 'Overdrachtsdossier';
    return 'de BeleidsBibliotheek';
}
function syncRpSectie(ctx) {
    var sel = document.getElementById('rpSectie');
    if (!sel) return;
    var hoofdstuk = ctx.split(' \u2192 ')[0];
    for (var i = 0; i < sel.options.length; i++) {
        if (sel.options[i].value === hoofdstuk) { sel.selectedIndex = i; return; }
    }
    sel.selectedIndex = 0;
}
function toggleReactiePanel() {
    var panel = document.getElementById('rpPanel');
    var overlay = document.getElementById('rpOverlay');
    var fab = document.getElementById('fabReactie');
    var open = panel.classList.toggle('rp-open');
    overlay.classList.toggle('rp-overlay-open', open);
    fab.style.display = open ? 'none' : '';
    if (open) {
        var ctx = detectContext();
        document.getElementById('rpContext').textContent = ctx;
        syncRpSectie(ctx);
    }
}

