# ---- Parse ALL naam|link keys per hoofdstuk ----
bbv_naam_links = {}
in_per_bbv = False
current_bbv = None
for line in appjs.split('\n'):
    if 'const BELEIDSNOTA_PER_HOOFDSTUK_BBV = {' in line:
